B.OH=s(["J\u2019ai sacrifi\xe9 ma main pour encha\xeener un loup.","Je suis le dieu manchot de la justice et de la guerre h\xe9ro\xefque.","Mon nom est synonyme de courage."],t.s)
B.Tk=new A.cW("TYR",B.OH)
B.Py=s(["J\u2019ai \xe9chang\xe9 un \u0153il contre la sagesse.","Mes deux corbeaux parcourent le monde pour m\u2019informer.","Je suis le P\xe8re de Tout, r\xe9gnant depuis Asgard."],t.s)
B.Te=new A.cW("ODIN",B.Py)
B.PH=s(["Mon char est tir\xe9 par des boucs.","Je suis le protecteur de Midgard et le fils d\u2019Odin.","Le tonnerre gronde quand je lance mon marteau."],t.s)
B.Tg=new A.cW("THOR",B.PH)
B.NW=s(["Je suis le p\xe8re de monstres et le ma\xeetre de la tromperie.","Mon sang s\u2019est m\xeal\xe9 \xe0 celui d\u2019Odin.","Je change de forme comme je change d\u2019avis."],t.s)
B.Tf=new A.cW("LOKI",B.NW)
B.Pn=s(["Je pleure des larmes d\u2019or pour mon \xe9poux parti.","Je r\xe8gne sur le F\xf3lkvangr et re\xe7ois la moiti\xe9 des guerriers morts.","Mon collier, Br\xedsingamen, est le plus beau des tr\xe9sors."],t.s)
B.Tj=new A.cW("FREYA",B.Pn)
B.Om=s(["Je connais le destin de tous, mais je garde le silence.","Je suis l\u2019\xe9pouse d\u2019Odin et la reine d\u2019Asgard.","J\u2019ai pleur\xe9 la mort de mon fils lumineux."],t.s)
B.T9=new A.cW("FRIGG",B.Om)
B.Oh=s(["Ma m\xe2choire, une fois ouverte, touche le ciel et la terre.","Les dieux m\u2019ont encha\xeen\xe9 par la ruse avec un ruban de soie.","Je d\xe9vorerai Odin lors de la derni\xe8re bataille."],t.s)
B.Tb=new A.cW("FENRIR",B.Oh)
B.Nw=s(["Je suis la forteresse des dieux Ases.","Mes murs ont \xe9t\xe9 construits par un g\xe9ant et son cheval.","Le pont arc-en-ciel m\xe8ne \xe0 mes portes."],t.s)
B.T5=new A.cW("ASGARD",B.Nw)
B.Pc=s(["Chaque matin, je pars pour ne revenir qu\u2019au soir.","Je suis la Pens\xe9e qui vole pour le P\xe8re de Tout.","Mon fr\xe8re est la M\xe9moire."],t.s)
B.To=new A.cW("HUGINN",B.Pc)
B.Pq=s(["Je suis un pont de feu gard\xe9 par un dieu vigilant.","Mes trois couleurs relient le monde des hommes \xe0 celui des dieux.","Je me briserai sous le poids des g\xe9ants \xe0 la fin des temps."],t.s)
B.Tl=new A.cW("BIFROST",B.Pq)
B.P8=s(["Je reviens toujours \xe0 la main de mon ma\xeetre.","Mon vol dans le ciel est le son du tonnerre.","Je suis le broyeur, terreur des g\xe9ants."],t.s)
B.Tc=new A.cW("MJOLNIR",B.P8)
B.PF=s(["Je suis le royaume des mortels.","Un serpent g\xe9ant entoure mes c\xf4tes.","Je suis prot\xe9g\xe9 par le fils d\u2019Odin au marteau."],t.s)
B.T3=new A.cW("MIDGARD",B.PF)
B.P9=s(["Mon toit est couvert de boucliers dor\xe9s.","Ici, les guerriers d\u2019\xe9lite festoient et combattent chaque jour.","Je suis le grand hall d\u2019Odin pour les morts valeureux."],t.s)
B.T8=new A.cW("VALHALLA",B.P9)
B.NS=s(["Je suis la lance qui ne manque jamais sa cible.","Mon propri\xe9taire s\u2019est pendu \xe0 un arbre avec moi dans le flanc.","Un serment pr\xeat\xe9 sur ma pointe est inviolable."],t.s)
B.Tm=new A.cW("GUNGNIR",B.NS)
B.NO=s(["Je suis le cr\xe9puscule des dieux.","Le soleil deviendra noir et la terre sombrera dans la mer.","Je suis une fin, mais aussi un nouveau commencement."],t.s)
B.Tn=new A.cW("RAGNAROK",B.NO)
B.Pf=s(["Mes racines unissent trois mondes.","Je suis l\u2019Arbre du Monde, un fr\xeane \xe9ternel.","Un aigle, un \xe9cureuil et un dragon vivent en moi."],t.s)
B.Ta=new A.cW("YGGDRASIL",B.Pf)
B.OO=s(["Nous chevauchons les cieux, choisissant les morts au combat.","Nous servons Odin, portant les h\xe9ros au Valhalla.","Nos noms r\xe9sonnent sur les champs de bataille."],t.s)
B.Tp=new A.cW("VALKYRIES",B.OO)
B.Ok=s(["Je suis le royaume des g\xe9ants, au-del\xe0 de Midgard.","Mes montagnes sont froides et mes habitants redoutables.","C\u2019est ici que Thor vient souvent chercher querelle."],t.s)
B.T4=new A.cW("JOTUNHEIM",B.Ok)
