B.Ti=new A.cW("NIDAVELLIR",B.OE)
B.PB=s(["Je suis la source de toutes les rivi\xe8res, au c\u0153ur de Niflheim.","Mon chaudron bouillonne, et mes eaux g\xe8lent tout sur leur passage.","C\u2019est de moi que naissent les onze fleuves d\u2019\xc9liv\xe1gar."],t.s)
B.Td=new A.cW("HVERGELMIR",B.PB)
