s($,"bj0","NY",()=>{var q,p,o,n,m,l,k,j,i,h,g=63.66197723675813*A.rl(50)/100,f=A.aR7(0.1,50),e=$.ws[0],d=$.ws[1],c=$.ws[2],b=e*0.401288+d*0.650173+c*-0.051461,a=e*-0.250268+d*1.204414+c*0.045854,a0=e*-0.002079+d*0.048952+c*0.953127,a1=A.aPc(0.59,0.69,0.9999999999999998),a2=1-0.2777777777777778*A.bew((-g-42)/92)
if(a2>1)a2=1
else if(a2<0)a2=0
q=A.b([a2*(100/b)+1-a2,a2*(100/a)+1-a2,a2*(100/a0)+1-a2],t.n)
e=5*g
p=1/(e+1)
o=p*p*p*p
n=1-o
m=o*g+0.1*n*n*A.NE(e,0.3333333333333333)
l=A.rl(f)/$.ws[1]
e=A.bfH(l)
k=0.725/A.NE(l,0.2)
j=[A.NE(m*q[0]*b/100,0.42),A.NE(m*q[1]*a/100,0.42),A.NE(m*q[2]*a0/100,0.42)]
d=j[0]
c=j[1]
i=j[2]
h=[400*d/(d+27.13),400*c/(c+27.13),400*i/(i+27.13)]
return new A.aux(l,(40*h[0]+20*h[1]+h[2])/20*k,k,k,a1,1,q,m,A.NE(m,0.25),1.48+e)})
s($,"bl0","aNM",()=>{var q=t.s,p=A.aPa(A.cJ("Le dieu de la lumi\xe8re, de la beaut\xe9 et de la puret\xe9, fils d\u2019Odin et de Frigg. Ador\xe9 de tous, sa pr\xe9sence apportait joie et paix. Un r\xeave pr\xe9monitoire de sa propre mort poussa sa m\xe8re, Frigg, \xe0 faire jurer \xe0 toute chose dans la cr\xe9ation de ne jamais lui nuire. Seul le gui, jug\xe9 trop jeune et inoffensif, fut oubli\xe9. Sa mort tragique, orchestr\xe9e par Loki, fut le premier et plus terrible pr\xe9sage de la venue du Ragnar\xf6k, la fin des temps.","baldr",A.b(["Baldr","Ragnar\xf6k"],q),"Baldr le Bon"),!0,t.cr)
B.b.K(p,A.cJ("D\xe9esse de l\u2019amour, du mariage et de la maternit\xe9, \xe9pouse d\u2019Odin et reine d\u2019Asgard. Elle est la m\xe8re de Baldr, le dieu bien-aim\xe9. Dot\xe9e du don de proph\xe9tie, elle conna\xeet le destin de tous les \xeatres, y compris celui de son fils, mais ne peut le changer. Son amour maternel la poussa \xe0 prot\xe9ger Baldr en faisant pr\xeater serment \xe0 toute la cr\xe9ation, une tentative d\xe9sesp\xe9r\xe9e qui fut d\xe9jou\xe9e par la ruse de Loki.","frigg",A.b(["Frigg","Odin","Baldr"],q),"Frigg la M\xe8re"))
B.b.K(p,A.cJ("La seule plante capable de blesser le dieu Baldr. Frigg, dans sa qu\xeate pour prot\xe9ger son fils, avait fait jurer \xe0 chaque \xe9l\xe9ment de la nature de ne jamais lui faire de mal. Elle omit cependant le gui, le consid\xe9rant trop jeune et faible pour repr\xe9senter une menace. Loki, le dieu de la malice, exploita cette faille. Il fabriqua une fl\xe8che de gui et la donna \xe0 H\xf6d, le fr\xe8re aveugle de Baldr, qui le tua involontairement.","gui",A.b(["Gui","Baldr","Loki"],q),"Le Gui Mortel"))
B.b.K(p,A.cJ("Le dieu du tonnerre, fils d\u2019Odin et de J\xf6rd (la Terre). Protecteur d\xe9vou\xe9 d\u2019Asgard et des humains (Midgard), il est connu pour sa force prodigieuse et son courage sans faille. Arm\xe9 de son marteau Mj\xf6llnir, qui revient toujours dans sa main, de sa ceinture Megingjord qui d\xe9cuple sa force, et de ses gants de fer J\xe1rngreipr, il combat sans rel\xe2che les g\xe9ants et les monstres qui menacent l\u2019ordre cosmique.","thor",A.b(["Thor","Mj\xf6llnir"],q),"Thor le Protecteur"))
B.b.K(p,A.cJ("Le marteau l\xe9gendaire de Thor, forg\xe9 par les nains Brokkr et Sindri. Symbole de protection et de destruction, il est capable de contr\xf4ler la foudre et le tonnerre. Mj\xf6llnir ne manque jamais sa cible et revient toujours \xe0 son porteur apr\xe8s avoir \xe9t\xe9 lanc\xe9. C\u2019est l\u2019une des armes les plus puissantes des dieux, indispensable dans la lutte \xe9ternelle contre les forces du chaos, notamment les g\xe9ants.","mjollnir",A.b(["Mj\xf6llnir","Thor"],q),"Mj\xf6llnir"))
B.b.K(p,A.cJ("Le redoutable roi des g\xe9ants de glace (J\xf6tun) qui commit l\u2019audace de voler Mj\xf6llnir, le marteau de Thor. En \xe9change de sa restitution, il exigea la main de la d\xe9esse Freyja. Pour r\xe9cup\xe9rer son arme, Thor se d\xe9guisa en Freyja, accompagn\xe9 de Loki en servante. La ruse fonctionna, et une fois le marteau en sa possession, Thor massacra Thrym et toute sa cour, restaurant l\u2019honneur des dieux.","thrym",A.b(["Thrym","Freyja","Mj\xf6llnir"],q),"Thrym le G\xe9ant"))
B.b.K(p,A.cJ("Le loup gigantesque, l\u2019un des trois enfants monstrueux de Loki et de la g\xe9ante Angrboda. Les dieux, effray\xe9s par sa croissance rapide et les proph\xe9ties annon\xe7ant qu\u2019il causerait leur perte, d\xe9cid\xe8rent de l\u2019encha\xeener. Apr\xe8s avoir bris\xe9 deux cha\xeenes, il fut finalement li\xe9 par le lien magique Gleipnir. Lors du Ragnar\xf6k, il se lib\xe9rera et accomplira son destin en d\xe9vorant Odin, avant d\u2019\xeatre tu\xe9 par Vidar, le fils d\u2019Odin.","fenrir",A.b(["Fenrir","Loki","Odin","Ragnar\xf6k"],q),"Fenrir le Loup"))
B.b.K(p,A.cJ("Le dieu de la guerre, du droit et de la justice. D\u2019un courage exemplaire, il est le seul dieu qui osa approcher le loup Fenrir lorsque celui-ci devint trop grand et mena\xe7ant. Pour prouver aux loup qu\u2019ils ne voulaient pas le pi\xe9ger avec la cha\xeene magique Gleipnir, T\xfdr pla\xe7a sa main droite dans la gueule de la b\xeate. Quand Fenrir comprit qu\u2019il \xe9tait encha\xeen\xe9, il lui arracha la main. Ce sacrifice permit de neutraliser le loup jusqu\u2019au Ragnar\xf6k.","tyr",A.b(["Tyr","Fenrir"],q),"T\xfdr le Sacrifi\xe9"))
B.b.K(p,A.cJ("La cha\xeene magique forg\xe9e par les nains pour lier le loup Fenrir. Contrairement aux lourdes cha\xeenes pr\xe9c\xe9dentes que Fenrir avait bris\xe9es, Gleipnir \xe9tait aussi fin et souple qu\u2019un ruban de soie. Il \xe9tait fabriqu\xe9 \xe0 partir de six ingr\xe9dients impossibles : le son des pas d\u2019un chat, la barbe d\u2019une femme, les racines d\u2019une montagne, les tendons d\u2019un ours, le souffle d\u2019un poisson et la salive d\u2019un oiseau. C\u2019est le seul lien que Fenrir ne put jamais briser.","gleipnir",A.b(["Gleipnir","Fenrir"],q),"Gleipnir"))
B.b.K(p,A.cJ("Le premier \xeatre vivant, un g\xe9ant primordial n\xe9 de la rencontre du feu de Muspelheim et de la glace de Niflheim dans le vide du Ginnungagap. De sa sueur naquirent les premiers g\xe9ants. Il fut nourri par la vache cosmique Audhumla. Finalement, il fut tu\xe9 par les dieux Odin et ses fr\xe8res, Vili et V\xe9. De son corps, ils cr\xe9\xe8rent le monde : sa chair devint la terre, son sang les oc\xe9ans, ses os les montagnes et son cr\xe2ne la vo\xfbte c\xe9leste.","ymir",A.b(["Ymir"],q),"Ymir le G\xe9ant Primordial"))
B.b.K(p,A.cJ("La vache primordiale, n\xe9e de la fonte des glaces au commencement des temps, tout comme le g\xe9ant Ymir. De ses pis coulaient quatre rivi\xe8res de lait qui nourrirent Ymir et permirent sa survie. En l\xe9chant un bloc de glace sal\xe9, Audhumla mit \xe0 jour Buri, le premier des dieux et l\u2019anc\xeatre d\u2019Odin. Elle est donc \xe0 l\u2019origine des deux lign\xe9es, celle des g\xe9ants et celle des dieux, qui s\u2019affronteront durant le Ragnar\xf6k.","audhumla",A.b(["Audhumla","Ymir","Buri"],q),"Audhumla la Vache Cosmique"))
B.b.K(p,A.cJ("Le vide b\xe9ant et silencieux qui existait avant toute cr\xe9ation. C\u2019\xe9tait un ab\xeeme sans fond, bord\xe9 au nord par le royaume glacial de Niflheim et au sud par le royaume ardent de Muspelheim. C\u2019est de la rencontre entre le souffle glac\xe9 de Niflheim et les \xe9tincelles br\xfblantes de Muspelheim au centre du Ginnungagap que la vie a \xe9merg\xe9, donnant naissance au g\xe9ant primordial Ymir et \xe0 la vache cosmique Audhumla.","ginnungagap",A.b(["Ginnungagap"],q),"Le Ginnungagap"))
B.b.K(p,A.cJ("D\xe9esse de la fertilit\xe9, de la terre et des moissons, \xe9pouse de Thor. Elle \xe9tait c\xe9l\xe8bre pour sa magnifique chevelure d\u2019or pur, qui symbolisait les champs de bl\xe9 m\xfbr. Un jour, par malice, Loki lui coupa les cheveux. Furieux, Thor for\xe7a Loki \xe0 r\xe9parer son m\xe9fait. Loki dut alors commander aux nains de forger une nouvelle chevelure d\u2019or, qui poussait comme de vrais cheveux, ainsi que d\u2019autres tr\xe9sors pour les dieux.","sif",A.b(["Sif","Thor"],q),"Sif aux Cheveux d\u2019Or"))
B.b.K(p,A.cJ("Deux fr\xe8res nains, ma\xeetres forgerons r\xe9put\xe9s pour leur habilet\xe9 in\xe9gal\xe9e. Suite \xe0 une ruse de Loki, ils firent le pari avec le dieu qu\u2019ils pourraient cr\xe9er des objets plus merveilleux que ceux cr\xe9\xe9s par les fils d\u2019Ivaldi. Ils forg\xe8rent ainsi trois tr\xe9sors exceptionnels : le sanglier d\u2019or Gullinbursti pour Freyr, l\u2019anneau d\u2019or Draupnir pour Odin, et le plus c\xe9l\xe8bre de tous, le marteau Mj\xf6llnir pour Thor, malgr\xe9 un d\xe9faut mineur (son manche court) d\xfb \xe0 une intervention de Loki.","brokkr_sindri",A.b(["Brokkr","Sindri","Mj\xf6llnir"],q),"Brokkr et Sindri"))
B.b.K(p,A.cJ('L\u2019anneau magique en or pur poss\xe9d\xe9 par Odin, l\u2019un des plus grands tr\xe9sors des dieux. Forg\xe9 par les nains Brokkr et Sindri, son nom signifie "le goutteur". Il poss\xe8de la capacit\xe9 extraordinaire de se multiplier : toutes les neuf nuits, il produit huit nouveaux anneaux d\u2019or de poids et de qualit\xe9 identiques. Draupnir fut plac\xe9 par Odin sur le b\xfbcher fun\xe9raire de son fils Baldr en signe de respect, mais lui fut retourn\xe9 du royaume des morts.',"draupnir",A.b(["Draupnir","Odin"],q),"Draupnir l\u2019Anneau"))
B.b.K(p,A.cJ('La lance infaillible d\u2019Odin, qui ne manque jamais sa cible. Son nom signifie "la chancelante". Elle fut \xe9galement forg\xe9e par des nains, les fils d\u2019Ivaldi, et obtenue par Loki. Un serment grav\xe9 sur sa pointe garantit sa pr\xe9cision. Gungnir est un symbole du pouvoir et de l\u2019autorit\xe9 d\u2019Odin en tant que dieu de la guerre. C\u2019est en se sacrifiant, pendu \xe0 Yggdrasil et transperc\xe9 par sa propre lance, qu\u2019Odin acquit la connaissance des runes.',"gungnir",A.b(["Gungnir","Odin"],q),"Gungnir la Lance"))
B.b.K(p,A.cJ("Un g\xe9ant (J\xf6tunn) qui se pr\xe9senta aux dieux sous les traits d\u2019un simple b\xe2tisseur. Il leur proposa un march\xe9 audacieux : construire une forteresse imprenable autour d\u2019Asgard en seulement trois saisons. En paiement, il r\xe9clamait la d\xe9esse Freyja, ainsi que le Soleil et la Lune. Les dieux accept\xe8rent, pensant la t\xe2che impossible. Mais le g\xe9ant, aid\xe9 de son cheval magique Svadilfari, avan\xe7a si vite que les dieux prirent peur et demand\xe8rent \xe0 Loki d\u2019intervenir.","hrimthurs",A.b(["Hrimthurs","Freyja","Asgard"],q),"Hrimthurs le B\xe2tisseur"))
B.b.K(p,A.cJ('Le cheval magique et exceptionnellement fort du g\xe9ant b\xe2tisseur Hrimthurs. Son nom signifie "voyageur malchanceux". La rapidit\xe9 et la puissance de Svadilfari \xe9taient telles qu\u2019il permettait \xe0 son ma\xeetre de construire la muraille d\u2019Asgard \xe0 une vitesse prodigieuse, mena\xe7ant de faire gagner le pari au g\xe9ant. Pour saboter le travail, Loki se transforma en une magnifique jument et attira Svadilfari loin de son ma\xeetre, emp\xeachant ainsi l\u2019ach\xe8vement du mur \xe0 temps.',"svadilfari",A.b(["Svadilfari","Hrimthurs"],q),"Svadilfari le Cheval"))
B.b.K(p,A.cJ("Le cheval d\u2019Odin, n\xe9 de l\u2019union de Loki transform\xe9 en jument et de Svadilfari. Le plus rapide de tous les chevaux des neuf mondes, capable de galoper sur terre, sur mer et dans les airs. Sleipnir est le fid\xe8le destrier d\u2019Odin, le transportant \xe0 travers les mondes lors de ses voyages. Ses huit pattes symbolisent sa vitesse surnaturelle et sa capacit\xe9 \xe0 se mouvoir entre les dimensions.","sleipnir",A.b(["Sleipnir","Odin","Loki","Svadilfari"],q),"Sleipnir le Cheval \xe0 Huit Pattes"))
B.b.K(p,A.cJ("Le pont arc-en-ciel vibrant et chatoyant qui relie Midgard, le monde des hommes, \xe0 Asgard, la forteresse des dieux. Il est d\xe9crit comme \xe9tant fait de feu, d\u2019air et d\u2019eau, et est plus solide que n\u2019importe quelle autre structure. Il est gard\xe9 en permanence par le dieu Heimdall, qui en surveille l\u2019acc\xe8s depuis son poste de garde, Himinbj\xf6rg. Le Bifrost s\u2019effondrera lors du Ragnar\xf6k sous le poids des g\xe9ants de feu men\xe9s par Surt.","bifrost",A.b(["Bifrost","Asgard","Heimdall"],q),"Bifrost"))
B.b.K(p,A.cJ("Le dieu de la po\xe9sie, de l\u2019\xe9loquence et de la musique. Il est l\u2019\xe9poux d\u2019Idunn, la gardienne des pommes de jouvence. Bragi est repr\xe9sent\xe9 comme un vieil homme sage \xe0 la longue barbe, dont les paroles sont si belles qu\u2019elles charment tous ceux qui les entendent. Il est le scalde (po\xe8te) de la cour des dieux \xe0 Asgard, accueillant les guerriers valeureux arrivant au Valhalla avec ses chants \xe9piques qui relatent leurs hauts faits et la gloire des dieux.","bragi",A.b(["Bragi","Idunn"],q),"Bragi"))
B.b.K(p,A.cJ('Le magnifique et l\xe9gendaire collier de la d\xe9esse Freyja. Son nom signifie "le bijou de feu". Il fut forg\xe9 par quatre nains experts. Pour l\u2019obtenir, Freyja dut passer une nuit avec chacun d\u2019eux. Ce collier est le symbole de sa beaut\xe9, de sa s\xe9duction et de son pouvoir sur l\u2019amour et le d\xe9sir. Il fut vol\xe9 par Loki et r\xe9cup\xe9r\xe9 par Heimdall apr\xe8s un combat acharn\xe9 o\xf9 tous deux prirent la forme de phoques.',"brisingamen",A.b(["Brisingamen","Freyja"],q),"Brisingamen"))
B.b.K(p,A.cJ("D\xe9esse majeure de la mythologie nordique, associ\xe9e \xe0 l\u2019amour, la beaut\xe9, la fertilit\xe9, mais aussi \xe0 la guerre, la richesse et la magie (le seidr). S\u0153ur jumelle de Freyr, elle est la plus belle des d\xe9esses. Elle r\xe8gne sur son propre royaume, F\xf3lkvangr, o\xf9 elle accueille la moiti\xe9 des guerriers morts h\xe9ro\xefquement au combat, l\u2019autre moiti\xe9 allant au Valhalla d\u2019Odin. Elle poss\xe8de le collier Brisingamen et un char tir\xe9 par deux chats.","freyja",A.b(["Freyja","Folkvangr"],q),"Freyja"))
B.b.K(p,A.cJ('La "Corne retentissante" du dieu Heimdall. Il l\u2019utilise pour surveiller le pont Bifrost. Le son de cette corne est si puissant qu\u2019il peut \xeatre entendu dans les neuf mondes. Heimdall ne sonnera du Gjallarhorn qu\u2019une seule fois, mais ce sera pour un \xe9v\xe9nement capital : il l\u2019utilisera pour alerter tous les dieux du d\xe9but du Ragnar\xf6k, lorsque les g\xe9ants et les monstres lanceront leur assaut final contre Asgard.',"gjallarhorn",A.b(["Gjallarhorn","Heimdall","Ragnar\xf6k"],q),"Gjallarhorn"))
B.b.K(p,A.cJ("Le gardien vigilant d\u2019Asgard, post\xe9 \xe0 l\u2019entr\xe9e du pont Bifrost pour emp\xeacher les g\xe9ants d\u2019envahir le royaume des dieux. N\xe9 de neuf m\xe8res, il poss\xe8de des sens surhumains : sa vue per\xe7ante lui permet de voir \xe0 des centaines de lieues et son ou\xefe est si fine qu\u2019il peut entendre l\u2019herbe pousser. Il est le d\xe9tenteur de la corne Gjallarhorn. Lors du Ragnar\xf6k, il sera le dernier \xe0 tomber, tuant son \xe9ternel ennemi Loki dans un combat o\xf9 ils s\u2019entretueront.","heimdall",A.b(["Heimdall","Asgard","Bifrost"],q),"Heimdall"))
B.b.K(p,A.cJ("Fille de Loki et de la g\xe9ante Angrboda, s\u0153ur du loup Fenrir et du serpent J\xf6rmungandr. Bannie par Odin, elle devint la souveraine du royaume des morts, Helheim. Elle est souvent repr\xe9sent\xe9e avec un corps \xe0 moiti\xe9 vivant et \xe0 moiti\xe9 d\xe9compos\xe9. Elle r\xe8gne sur les \xe2mes de ceux qui sont morts de maladie ou de vieillesse, par opposition aux guerriers morts au combat qui vont au Valhalla ou \xe0 F\xf3lkvangr. Son pouvoir sur les morts est absolu.","hel",A.b(["Hel","Helheim","Loki"],q),"Hel"))
B.b.K(p,A.cJ("Le royaume des morts, l\u2019un des neuf mondes, gouvern\xe9 par la d\xe9esse Hel. C\u2019est un lieu sombre, froid et brumeux, situ\xe9 dans les profondeurs de Niflheim. C\u2019est l\xe0 que vont les \xe2mes de ceux qui ne sont pas morts de mani\xe8re h\xe9ro\xefque au combat. L\u2019entr\xe9e de Helheim est gard\xe9e par le chien monstrueux Garm. M\xeame les dieux ne peuvent en r\xe9chapper sans la permission de Hel, comme le montre la vaine tentative de ramener Baldr \xe0 la vie.","helheim",A.b(["Helheim","Hel"],q),"Helheim"))
B.b.K(p,A.cJ('L\u2019\xe9p\xe9e \xe9tincelante du dieu gardien Heimdall. Son nom signifie "t\xeate d\u2019homme", possiblement en r\xe9f\xe9rence \xe0 un pommeau sculpt\xe9. Comme son propri\xe9taire, l\u2019\xe9p\xe9e est un symbole de vigilance et de protection pour Asgard. Bien que moins c\xe9l\xe8bre que d\u2019autres armes divines comme Mj\xf6llnir ou Gungnir, Hofund est une arme puissante qui sera utilis\xe9e par Heimdall lors de son combat final et mutuellement destructeur contre Loki durant le Ragnar\xf6k.',"hofund",A.b(["Hofund","Heimdall"],q),"Hofund"))
B.b.K(p,A.cJ('Les deux corbeaux perch\xe9s sur les \xe9paules d\u2019Odin. Leurs noms signifient "Pens\xe9e" (Huginn) et "M\xe9moire" (Muninn). Chaque matin, Odin les envoie parcourir les neuf mondes. \xc0 leur retour, ils lui murmurent \xe0 l\u2019oreille tout ce qu\u2019ils ont vu et entendu. Ils sont les sources d\u2019information du P\xe8re de Tout, lui conf\xe9rant une connaissance quasi omnisciente des \xe9v\xe9nements pass\xe9s, pr\xe9sents et \xe0 venir, et l\u2019aidant dans sa qu\xeate insatiable de sagesse.',"huginnmuninn",A.b(["Huginn","Muninn","Odin"],q),"Huginn et Muninn"))
B.b.K(p,A.cJ("D\xe9esse de la jeunesse et de l\u2019\xe9ternit\xe9, \xe9pouse du dieu po\xe8te Bragi. Elle est la gardienne des pommes d\u2019or, des fruits magiques qui conf\xe8rent aux dieux leur jeunesse et leur immortalit\xe9. Sans ces pommes, les dieux vieilliraient et mourraient comme de simples mortels. Idunn fut un jour enlev\xe9e par le g\xe9ant Thjazi avec la complicit\xe9 de Loki, for\xe7ant les dieux \xe0 vieillir jusqu\u2019\xe0 ce que Loki soit contraint de la ramener \xe0 Asgard.","idunn",A.b(["Idunn","Pommes d\u2019or"],q),"Idunn"))
B.b.K(p,A.cJ('Le Serpent de Midgard, l\u2019un des trois enfants de Loki et de la g\xe9ante Angrboda. Jet\xe9 dans l\u2019oc\xe9an qui entoure Midgard par Odin, il grandit de mani\xe8re si d\xe9mesur\xe9e qu\u2019il finit par encercler le monde des hommes et se mordre la queue, d\u2019o\xf9 son surnom de "Serpent-Monde". Il est l\u2019ennemi jur\xe9 de Thor. Lors du Ragnar\xf6k, les deux adversaires s\u2019affronteront dans un combat titanesque. Thor tuera J\xf6rmungandr mais succombera \xe0 son venin neuf pas plus loin.',"jormungandr",A.b(["J\xf6rmungandr","Loki","Midgard"],q),"J\xf6rmungandr"))
B.b.K(p,A.cJ("Dieu de la ruse, de la discorde et de la m\xe9tamorphose. Fils de g\xe9ants mais admis parmi les dieux Ases, il est le fr\xe8re de sang d\u2019Odin. Intelligent et charmeur, il utilise ses talents pour aider les dieux \xe0 se sortir de situations difficiles, mais sa nature malicieuse et chaotique le pousse aussi \xe0 \xeatre \xe0 l\u2019origine de la plupart de leurs probl\xe8mes. P\xe8re de monstres comme Fenrir, J\xf6rmungandr et Hel, son r\xf4le devient de plus en plus sombre, jusqu\u2019\xe0 provoquer le Ragnar\xf6k.","loki",A.b(["Loki"],q),"Loki"))
B.b.K(p,A.cJ("Dieu de la mer, du vent, de la p\xeache et de la richesse. Il appartient \xe0 la famille des dieux Vanes, mais vint vivre \xe0 Asgard avec ses enfants, Freyja et Freyr, comme otage apr\xe8s la guerre entre les Ases et les Vanes. Il est invoqu\xe9 par les marins pour des voyages s\xfbrs et de bonnes prises. Son mariage malheureux avec la g\xe9ante Skadi, qui aimait les montagnes tandis qu\u2019il aimait la mer, illustre l\u2019opposition entre ces deux mondes.","njord",A.b(["Njord","Freyja","Freyr"],q),"Njord"))
B.b.K(p,A.cJ("Le P\xe8re de Tout, le dieu principal du panth\xe9on nordique. Dieu de la sagesse, de la guerre, de la mort, de la po\xe9sie et de la magie (runes). Il r\xe8gne sur Asgard depuis son tr\xf4ne Hlidskjalf, d\u2019o\xf9 il peut observer les neuf mondes. Il a sacrifi\xe9 un \u0153il pour boire \xe0 la source de Mimir et acqu\xe9rir la connaissance universelle. Accompagn\xe9 de ses corbeaux Huginn et Muninn et de ses loups Geri et Freki, il pr\xe9pare les dieux et les hommes pour le Ragnar\xf6k.","odin",A.b(["Odin","Asgard"],q),"Odin"))
B.b.K(p,A.cJ("D\xe9esse g\xe9ante associ\xe9e \xe0 la chasse \xe0 l\u2019arc, \xe0 l\u2019hiver, aux montagnes et au ski. Fille du g\xe9ant Thjazi, elle se rendit \xe0 Asgard pour venger la mort de son p\xe8re, tu\xe9 par les dieux. En guise de compensation, les dieux lui offrirent d\u2019\xe9pouser l\u2019un d\u2019entre eux, mais elle devait le choisir en ne voyant que leurs pieds. Elle choisit Njord en pensant qu\u2019il s\u2019agissait de Baldr. Leur union fut un \xe9chec, Skadi ne supportant pas de vivre loin de ses montagnes enneig\xe9es.","skadi",A.b(["Skadi","Njord"],q),"Skadi"))
B.b.K(p,A.cJ("L\u2019Arbre Monde, un fr\xeane immense et \xe9ternel qui est au centre du cosmos nordique. Ses branches s\u2019\xe9tendent sur les neuf mondes et son tronc les relie. Trois racines principales le soutiennent, chacune plongeant dans une source : la source d\u2019Urd \xe0 Asgard, la source de Mimir au pays des g\xe9ants, et Hvergelmir \xe0 Niflheim. Yggdrasil est constamment attaqu\xe9 par diverses cr\xe9atures, comme le dragon Nidhogg qui ronge ses racines, mais il survit toujours, symbolisant la r\xe9silience de la vie.","yggdrasil",A.b(["Yggdrasil","Neuf Mondes"],q),"Yggdrasil"))
return p})
